import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY;

/**
 * Calls the Gemini Model to generate a response based strictly on the provided context.
 * 
 * @param query - The user's question
 * @param context - The retrieved snippets from our Knowledge Base
 * @returns The generated string response
 */
export const generateGeminiResponse = async (query: string, context: string): Promise<string> => {
  if (!apiKey) {
    return "Error: API Key is missing. Please configure the environment.";
  }

  const ai = new GoogleGenAI({ apiKey });

  // System Instruction: This implements the "Generation" part of RAG.
  // It forces the model to be a "Campus Guide" and reduces hallucinations by restricting it to the context.
  const systemInstruction = `
    You are the official UniNav Campus Guide AI.
    Your goal is to help students navigate the university.

    CRITICAL INSTRUCTION:
    You must answer the user's question using ONLY the context provided below.
    If the answer is not in the context, politely say you don't have that information in your database.
    Do not make up facts about the campus.

    Tone: Friendly, academic, and concise.
    Structure: Keep answers short (under 3 sentences) unless asked for details.
  `;

  const prompt = `
    CONTEXT INFORMATION:
    ${context}

    USER QUESTION:
    ${query}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Using Flash for low latency in a chat interface
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.3, // Low temperature for factual consistency
      }
    });

    return response.text || "I'm sorry, I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm experiencing connectivity issues with the campus brain. Please try again.";
  }
};

import { CAMPUS_DATA } from '../data/campusData';
import { SearchResult } from '../types';
import { generateGeminiResponse } from './geminiService';

/**
 * RETRIEVAL LOGIC (The "R" in RAG)
 * 
 * In a full implementation, this function would:
 * 1. Convert user query to vector embedding (e.g., OpenAI text-embedding-3-small).
 * 2. Query a vector DB (e.g., Pinecone) for nearest neighbors.
 * 
 * For this prototype, we implement a "Keyword Density Scoring" algorithm.
 * It tokenizes the query and finds documents with the highest overlap of significant terms.
 */
const retrieveDocuments = (query: string): SearchResult[] => {
  const queryTokens = query.toLowerCase().split(/\s+/).filter(t => t.length > 2); // Filter small words
  const results: SearchResult[] = [];

  // 1. Index Locations
  CAMPUS_DATA.locations.forEach(loc => {
    let score = 0;
    const content = `Location: ${loc.name}. Type: ${loc.type}. Details: ${loc.description}. Also known as: ${loc.aliases.join(', ')}`;
    const contentLower = content.toLowerCase();

    queryTokens.forEach(token => {
      if (contentLower.includes(token)) score += 3; // High weight for locations
    });

    if (score > 0) results.push({ content, score, source: 'Location Database' });
  });

  // 2. Index Routes
  CAMPUS_DATA.routes.forEach(route => {
    let score = 0;
    const fromLoc = CAMPUS_DATA.locations.find(l => l.id === route.fromId)?.name || route.fromId;
    const toLoc = CAMPUS_DATA.locations.find(l => l.id === route.toId)?.name || route.toId;

    const content = `Route from ${fromLoc} to ${toLoc}. Distance: ${route.distance}. Time: ${route.timeWalking}. Shuttle: ${route.shuttleAvailable ? 'Yes' : 'No'}. Fare: ${route.shuttleFare || 'N/A'}. Details: ${route.description}`;
    const contentLower = content.toLowerCase();

    queryTokens.forEach(token => {
      if (contentLower.includes(token)) score += 2;
    });

    if (score > 0) results.push({ content, score, source: 'Route Database' });
  });

  // 3. Index General Info
  CAMPUS_DATA.generalInfo.forEach(info => {
    let score = 0;
    const infoLower = info.toLowerCase();
    queryTokens.forEach(token => {
      if (infoLower.includes(token)) score += 1;
    });
    if (score > 0) results.push({ content: info, score, source: 'General Info' });
  });

  // Sort by score descending and take top 3 chunks
  return results.sort((a, b) => b.score - a.score).slice(0, 3);
};

/**
 * ORCHESTRATOR
 * Connects Retrieval and Generation.
 */
export const processQuery = async (userQuery: string): Promise<{ answer: string; context: string[] }> => {
  // Step 1: Retrieval
  const searchResults = retrieveDocuments(userQuery);

  if (searchResults.length === 0) {
    return {
      answer: "I couldn't find any specific information about that in the campus database. Could you try asking about specific buildings or routes?",
      context: ["No relevant documents found."]
    };
  }

  // Combine context for the LLM
  const contextStrings = searchResults.map(r => `[Source: ${r.source}] ${r.content}`);
  const combinedContext = contextStrings.join("\n\n");

  // Step 2: Generation
  const answer = await generateGeminiResponse(userQuery, combinedContext);

  return {
    answer,
    context: contextStrings
  };
};

