import React, { useState, useRef, useEffect } from 'react';

interface InputAreaProps {
  onSend: (text: string) => void;
  isLoading: boolean;
  voiceMode: boolean;
}

export const InputArea: React.FC<InputAreaProps> = ({ onSend, isLoading, voiceMode }) => {
  const [input, setInput] = useState('');
  const [isListening, setIsListening] = useState(false);

  // Use a ref to hold the recognition instance
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    // Setup Speech Recognition (Web Speech API)
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(transcript);
        onSend(transcript); // Auto-send on voice finish
        setIsListening(false);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech recognition error", event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, [onSend]);

  const handleSend = () => {
    if (input.trim() && !isLoading) {
      onSend(input);
      setInput('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
    } else {
      if (recognitionRef.current) {
        setIsListening(true);
        recognitionRef.current.start();
      } else {
        alert("Speech recognition not supported in this browser.");
      }
    }
  };

  return (
    <div className="bg-white border-t border-gray-200 p-4 sticky bottom-0 z-10 safe-area-bottom">
      <div className="max-w-3xl mx-auto flex items-end gap-2">

        {/* Voice Button */}
        {voiceMode && (
          <button
            onClick={toggleListening}
            disabled={isLoading}
            className={`flex-shrink-0 w-12 h-12 rounded-full flex items-center justify-center transition-all duration-200 ${
              isListening 
                ? 'bg-red-500 text-white animate-pulse ring-4 ring-red-100' 
                : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
            title="Press to speak"
          >
            <i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i>
          </button>
        )}

        {/* Text Input */}
        <div className="relative flex-grow">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={isListening ? "Listening..." : "Ask about routes, fares, or buildings..."}
            disabled={isLoading || isListening}
            rows={1}
            className="w-full bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-2xl focus:ring-brand-500 focus:border-brand-500 block w-full p-3 resize-none shadow-sm min-h-[48px] max-h-[120px]"
            style={{ overflow: 'hidden' }}
          />
        </div>

        {/* Send Button */}
        <button
          onClick={handleSend}
          disabled={!input.trim() || isLoading || isListening}
          className="flex-shrink-0 w-12 h-12 rounded-full bg-brand-600 text-white hover:bg-brand-700 disabled:opacity-50 disabled:hover:bg-brand-600 flex items-center justify-center transition-colors shadow-sm"
        >
          {isLoading ? (
            <i className="fas fa-spinner fa-spin"></i>
          ) : (
            <i className="fas fa-paper-plane"></i>
          )}
        </button>
      </div>

      {/* Helper Text for Academic Context */}
      <div className="max-w-3xl mx-auto mt-2 text-center">
        <p className="text-[10px] text-gray-400">
          Prototype Mode: Using Local RAG • Gemini 3 Flash • Browser Speech API
        </p>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Message } from './types';
import { processQuery } from './services/ragService';
import { ChatMessage } from './components/ChatMessage';
import { InputArea } from './components/InputArea';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'bot',
      content: "Hello! I'm UniNav, your multimodal campus guide. I can help you find routes, estimate fares, or locate buildings. Try asking: 'How do I get from the Main Gate to the Library?'",
      timestamp: Date.now()
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const [showDebug, setShowDebug] = useState(true); // Default on for academic demo
  const [voiceMode, setVoiceMode] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Multimodal Output: Text-to-Speech
  const speakResponse = (text: string) => {
    if (!voiceMode) return;

    // Cancel any current speaking
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    // Try to find a good English voice
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(v => v.lang.includes('en-US') && v.name.includes('Google')) || voices[0];
    if (preferredVoice) utterance.voice = preferredVoice;

    utterance.rate = 1.1; // Slightly faster for conversational feel
    window.speechSynthesis.speak(utterance);
  };

  const handleSendMessage = async (text: string) => {
    // 1. Add User Message
    const userMsg: Message = {
      id: uuidv4(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 2. Process via RAG Service
      const { answer, context } = await processQuery(text);

      // 3. Add Bot Message
      const botMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: answer,
        timestamp: Date.now(),
        retrievedContext: context // Critical for RAG demo
      };

      setMessages(prev => [...prev, botMsg]);

      // 4. Trigger Audio if Voice Mode is on
      speakResponse(answer);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: "I encountered a system error processing your request.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50">

      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-4 py-3 shadow-sm sticky top-0 z-20">
        <div className="max-w-3xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-brand-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-brand-200">
              <i className="fas fa-graduation-cap text-lg"></i>
            </div>
            <div>
              <h1 className="font-bold text-gray-900 leading-tight">UniNav</h1>
              <p className="text-xs text-gray-500 font-medium">Campus Navigation Prototype</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            {/* Toggle Debug/Context */}
            <button
              onClick={() => setShowDebug(!showDebug)}
              className={`p-2 rounded-lg text-xs font-bold transition-colors ${
                showDebug ? 'bg-brand-50 text-brand-700' : 'text-gray-400 hover:bg-gray-100'
              }`}
              title="Toggle RAG Context Visibility"
            >
              <i className="fas fa-code mr-1"></i> RAG
            </button>

             {/* Toggle Voice Mode */}
             <button
              onClick={() => {
                setVoiceMode(!voiceMode);
                window.speechSynthesis.cancel();
              }}
              className={`p-2 rounded-lg text-xs font-bold transition-colors ${
                voiceMode ? 'bg-red-50 text-red-600' : 'text-gray-400 hover:bg-gray-100'
              }`}
              title="Toggle Voice Mode"
            >
              <i className={`fas ${voiceMode ? 'fa-volume-up' : 'fa-volume-mute'} mr-1`}></i> Voice
            </button>
          </div>
        </div>
      </header>

      {/* Chat Area */}
      <main className="flex-1 overflow-y-auto p-4 scroll-smooth">
        <div className="max-w-3xl mx-auto flex flex-col min-h-full justify-end">
          {messages.length === 0 && (
            <div className="text-center text-gray-400 my-auto">
              <i className="fas fa-map-marked-alt text-6xl mb-4 text-gray-200"></i>
              <p>Start by asking about a location...</p>
            </div>
          )}

          {messages.map(msg => (
            <ChatMessage key={msg.id} message={msg} showDebug={showDebug} />
          ))}

          {isLoading && (
            <div className="flex justify-start mb-4">
               <div className="bg-white border border-gray-200 px-4 py-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
                 <div className="flex space-x-1">
                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                 </div>
                 <span className="text-xs text-gray-400 ml-2">Retrieving context...</span>
               </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>
      </main>

      {/* Input Area */}
      <InputArea 
        onSend={handleSendMessage} 
        isLoading={isLoading} 
        voiceMode={voiceMode} 
      />
    </div>
  );
};

