/**
 * Transcribes audio blob using Gemini 2.5 Flash.
 */
export const transcribeAudio = async (audioBase64: string): Promise<string> => {
  if (!apiKey) return "Error: API Key missing.";

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { mimeType: 'audio/wav', data: audioBase64 } },
          { text: "Transcribe the following audio accurately. Output only the transcription, no intro/outro." }
        ]
      }
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Failed to transcribe audio.");
  }
};

import { CAMPUS_DATA } from '../data/campusData';
import { SearchResult, CampusLocation } from '../types';
import { generateGeminiResponse } from './geminiService';

/**
 * RETRIEVAL LOGIC (The "R" in RAG)
 * 
 * In a full implementation, this function would:
 * 1. Convert user query to vector embedding (e.g., OpenAI text-embedding-3-small).
 * 2. Query a vector DB (e.g., Pinecone) for nearest neighbors.
 * 
 * For this prototype, we implement a "Keyword Density Scoring" algorithm.
 * It tokenizes the query and finds documents with the highest overlap of significant terms.
 */
const retrieveDocuments = (query: string, customLocations: CampusLocation[] = []): SearchResult[] => {
  const queryTokens = query.toLowerCase().split(/\s+/).filter(t => t.length > 2); // Filter small words
  const results: SearchResult[] = [];

  // Combine static and custom locations
  const allLocations = [...CAMPUS_DATA.locations, ...customLocations];

  // 1. Index Locations
  allLocations.forEach(loc => {
    let score = 0;
    const content = `Location: ${loc.name}. Type: ${loc.type}. Details: ${loc.description}. Also known as: ${loc.aliases.join(', ')}`;
    const contentLower = content.toLowerCase();

    queryTokens.forEach(token => {
      if (contentLower.includes(token)) score += 3; // High weight for locations
    });

    if (score > 0) results.push({ content, score, source: 'Location Database' });
  });

  // 2. Index Routes
  // Note: Routes in this mock are static, but we check against names of dynamic locations if needed
  CAMPUS_DATA.routes.forEach(route => {
    let score = 0;
    // We try to find names even for custom locations if IDs matched, but for now routes rely on static IDs.
    // However, if the query mentions a route keyword, we include it.

    const fromLoc = allLocations.find(l => l.id === route.fromId)?.name || route.fromId;
    const toLoc = allLocations.find(l => l.id === route.toId)?.name || route.toId;

    const content = `Route from ${fromLoc} to ${toLoc}. Distance: ${route.distance}. Time: ${route.timeWalking}. Shuttle: ${route.shuttleAvailable ? 'Yes' : 'No'}. Fare: ${route.shuttleFare || 'N/A'}. Details: ${route.description}`;
    const contentLower = content.toLowerCase();

    queryTokens.forEach(token => {
      if (contentLower.includes(token)) score += 2;
    });

    if (score > 0) results.push({ content, score, source: 'Route Database' });
  });

  // 3. Index General Info
  CAMPUS_DATA.generalInfo.forEach(info => {
    let score = 0;
    const infoLower = info.toLowerCase();
    queryTokens.forEach(token => {
      if (infoLower.includes(token)) score += 1;
    });
    if (score > 0) results.push({ content: info, score, source: 'General Info' });
  });

  // Sort by score descending and take top 3 chunks
  return results.sort((a, b) => b.score - a.score).slice(0, 3);
};

/**
 * ORCHESTRATOR
 * Connects Retrieval and Generation.
 */
export const processQuery = async (userQuery: string, customLocations: CampusLocation[] = []): Promise<{ answer: string; context: string[] }> => {
  // Step 1: Retrieval
  const searchResults = retrieveDocuments(userQuery, customLocations);

  if (searchResults.length === 0) {
    return {
      answer: "I couldn't find any specific information about that in the campus database. Could you try asking about specific buildings or routes?",
      context: ["No relevant documents found."]
    };
  }

  // Combine context for the LLM
  const contextStrings = searchResults.map(r => `[Source: ${r.source}] ${r.content}`);
  const combinedContext = contextStrings.join("\n\n");

  // Step 2: Generation
  const answer = await generateGeminiResponse(userQuery, combinedContext);

  return {
    answer,
    context: contextStrings
  };
};

import React, { useState, useRef } from 'react';

interface InputAreaProps {
  onSend: (text: string) => void;
  onSendAudio: (audioBlob: Blob) => void;
  isLoading: boolean;
  voiceMode: boolean;
}

export const InputArea: React.FC<InputAreaProps> = ({ onSend, onSendAudio, isLoading, voiceMode }) => {
  const [input, setInput] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const handleSend = () => {
    if (input.trim() && !isLoading) {
      onSend(input);
      setInput('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(chunksRef.current, { type: 'audio/wav' }); // or appropriate mime
        onSendAudio(audioBlob);

        // Stop all tracks
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Could not access microphone. Please ensure permissions are granted.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  return (
    <div className="bg-white border-t border-gray-200 p-4 sticky bottom-0 z-10 safe-area-bottom">
      <div className="max-w-3xl mx-auto flex items-end gap-2">

        {/* Voice Button */}
        {voiceMode && (
          <button
            onMouseDown={startRecording}
            onMouseUp={stopRecording}
            onTouchStart={startRecording}
            onTouchEnd={stopRecording}
            disabled={isLoading}
            className={`flex-shrink-0 w-12 h-12 rounded-full flex items-center justify-center transition-all duration-200 ${
              isRecording 
                ? 'bg-red-500 text-white animate-pulse ring-4 ring-red-100 scale-110' 
                : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
            title="Hold to speak"
          >
            <i className={`fas ${isRecording ? 'fa-microphone-slash' : 'fa-microphone'}`}></i>
          </button>
        )}

        {/* Text Input */}
        <div className="relative flex-grow">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={isRecording ? "Listening (Hold button)..." : "Ask about routes, fares, or buildings..."}
            disabled={isLoading || isRecording}
            rows={1}
            className="w-full bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-2xl focus:ring-brand-500 focus:border-brand-500 block w-full p-3 resize-none shadow-sm min-h-[48px] max-h-[120px]"
            style={{ overflow: 'hidden' }}
          />
        </div>

        {/* Send Button */}
        <button
          onClick={handleSend}
          disabled={!input.trim() || isLoading || isRecording}
          className="flex-shrink-0 w-12 h-12 rounded-full bg-brand-600 text-white hover:bg-brand-700 disabled:opacity-50 disabled:hover:bg-brand-600 flex items-center justify-center transition-colors shadow-sm"
        >
          {isLoading ? (
            <i className="fas fa-spinner fa-spin"></i>
          ) : (
            <i className="fas fa-paper-plane"></i>
          )}
        </button>
      </div>

      {/* Helper Text for Academic Context */}
      <div className="max-w-3xl mx-auto mt-2 text-center">
        <p className="text-[10px] text-gray-400">
          Prototype Mode: Using Local RAG • Gemini 2.5 Flash (Audio) • {voiceMode ? "Hold Mic to Speak" : "Text Only"}
        </p>
      </div>
    </div>
  );
};

