  const [isAddingLandmark, setIsAddingLandmark] = useState<{x: number, y: number} | null>(null);

  // Landmark Form State
  const [newLandmarkName, setNewLandmarkName] = useState("");

  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // --- Core Interactions ---

  const speakResponse = (text: string) => {
    if (!voiceMode) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(v => v.lang.includes('en-US') && v.name.includes('Google')) || voices[0];
    if (preferredVoice) utterance.voice = preferredVoice;
    utterance.rate = 1.1;
    window.speechSynthesis.speak(utterance);
  };

  const processUserRequest = async (text: string) => {
     // 1. Add User Message
     const userMsg: Message = {
      id: uuidv4(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };
    setMessages([...messages, userMsg]);
    setIsLoading(true);

    try {
      // 2. Process via RAG Service (passing dynamic locations)
      const { answer, context } = await processQuery(text, locations);

      // 3. Add Bot Message
      const botMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: answer,
        timestamp: Date.now(),
        retrievedContext: context
      };

      setMessages(prev => [...prev, botMsg]);
      speakResponse(answer);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: "System Error: Unable to process request.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAudioSend = async (audioBlob: Blob) => {
    setIsLoading(true);
