  // Landmark Form State
  const [newLandmarkName, setNewLandmarkName] = useState("");

  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // --- Core Interactions ---

  const speakResponse = (text: string) => {
    if (!voiceMode) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(v => v.lang.includes('en-US') && v.name.includes('Google')) || voices[0];
    if (preferredVoice) utterance.voice = preferredVoice;
    utterance.rate = 1.1;
    window.speechSynthesis.speak(utterance);
  };

  const processUserRequest = async (text: string) => {
     // 1. Add User Message
     const userMsg: Message = {
      id: uuidv4(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 2. Process via RAG Service (passing dynamic locations)
      const { answer, context } = await processQuery(text, locations);

      // 3. Add Bot Message
      const botMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: answer,
        timestamp: Date.now(),
        retrievedContext: context
      };

      setMessages(prev => [...prev, botMsg]);
      speakResponse(answer);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: "System Error: Unable to process request.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAudioSend = async (audioBlob: Blob) => {
    setIsLoading(true);
    // Add temporary message
    const tempId = uuidv4();
    setMessages(prev => [...prev, { id: tempId, role: 'user', content: "🎤 Processing audio...", timestamp: Date.now() }]);

    try {
      // Convert Blob to Base64
      const reader = new FileReader();
      reader.readAsDataURL(audioBlob);
      reader.onloadend = async () => {
        const base64Data = (reader.result as string).split(',')[1];

        // 1. Transcribe with Gemini
        const transcription = await transcribeAudio(base64Data);

        // Replace temp message with transcription
        setMessages(prev => prev.map(m => m.id === tempId ? { ...m, content: `🎤 "${transcription}"` } : m));

        if (!transcription) {
          setIsLoading(false);
          return;
        }

        // 2. Process as text query
        // Note: We don't call processUserRequest directly to avoid adding the message twice to state
        // We replicate the bot response part:
        const { answer, context } = await processQuery(transcription, locations);

        const botMsg: Message = {
            id: uuidv4(),
            role: 'bot',
            content: answer,
            timestamp: Date.now(),
            retrievedContext: context
        };
        setMessages(prev => [...prev, botMsg]);
        speakResponse(answer);
        setIsLoading(false);
      };
    } catch (e) {
      console.error(e);
      setMessages(prev => prev.map(m => m.id === tempId ? { ...m, content: "🎤 Error processing audio." } : m));
      setIsLoading(false);
    }
  };

  // --- Map Interactions ---

  const handleLocationClick = (loc: CampusLocation) => {
    processUserRequest(`Tell me about ${loc.name}`);
  };

  const handleMapClick = (x: number, y: number) => {
    setIsAddingLandmark({ x, y });
    setNewLandmarkName("");
  };

  const saveLandmark = () => {
    if (isAddingLandmark && newLandmarkName.trim()) {
      const newLoc: CampusLocation = {
        id: `custom_${uuidv4()}`,
        name: newLandmarkName,
        aliases: [],
        type: 'custom',
        description: `A custom landmark added by the user at ${newLandmarkName}.`,
        coords: isAddingLandmark
      };
      setLocations([...locations, newLoc]);
      setIsAddingLandmark(null);
      // Announce
      const msg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: `I've added "${newLandmarkName}" to the campus map. You can now ask me about it!`,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, msg]);
    }
  };

  const clearHistory = () => {
    if(confirm("Clear chat history?")) {
      setMessages([]);
      window.location.reload(); // Simple reload to reset state cleanly
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 md:flex-row">

      {/* Left Panel: Map & Tools (Desktop) / Top (Mobile) */}
      <div className="w-full md:w-1/3 bg-white border-b md:border-b-0 md:border-r border-gray-200 flex flex-col">
         <div className="p-4 border-b border-gray-100 flex justify-between items-center">
             <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white">
                  <i className="fas fa-graduation-cap"></i>
                </div>
                <h1 className="font-bold text-gray-800">UniNav</h1>
             </div>
             <button onClick={clearHistory} className="text-xs text-red-400 hover:text-red-600">
               <i className="fas fa-trash"></i> Reset
             </button>
         </div>

         <div className="p-4 flex-grow overflow-y-auto">
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Campus Map</h2>
            <CampusMap 
              locations={locations} 
              onLocationClick={handleLocationClick}
              onMapClick={handleMapClick}
            />
            <p className="text-[10px] text-gray-400 mt-2 text-center">
              Click a building to ask. Click empty space to add landmark.
            </p>

            {/* Add Landmark Form */}
            {isAddingLandmark && (
              <div className="mt-4 p-3 bg-brand-50 border border-brand-200 rounded-lg animate-in slide-in-from-top-2">
                <h3 className="text-sm font-bold text-brand-800 mb-2">New Landmark</h3>
                <input 
                  autoFocus
                  type="text" 
                  value={newLandmarkName}
                  onChange={e => setNewLandmarkName(e.target.value)}
                  placeholder="Enter Name (e.g., Coffee Stand)"
                  className="w-full text-sm border-gray-300 rounded-md mb-2 p-2"
                />
                <div className="flex gap-2">
                  <button onClick={saveLandmark} className="flex-1 bg-brand-600 text-white text-xs py-1.5 rounded hover:bg-brand-700">Save</button>
                  <button onClick={() => setIsAddingLandmark(null)} className="flex-1 bg-gray-200 text-gray-600 text-xs py-1.5 rounded hover:bg-gray-300">Cancel</button>
                </div>
              </div>
            )}
         </div>

         <div className="p-4 border-t border-gray-100 hidden md:block">
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Settings</h2>
            <div className="flex flex-col gap-2">
              <button
                onClick={() => setShowDebug(!showDebug)}
                className={`flex items-center justify-between p-2 rounded text-xs font-medium transition-colors ${
                  showDebug ? 'bg-slate-100 text-slate-700' : 'text-gray-400 hover:bg-gray-50'
                }`}
              >
                <span>Show RAG Context</span>
                <i className={`fas ${showDebug ? 'fa-toggle-on text-brand-500' : 'fa-toggle-off'}`}></i>
              </button>
              <button
                onClick={() => setVoiceMode(!voiceMode)}
                className={`flex items-center justify-between p-2 rounded text-xs font-medium transition-colors ${
                  voiceMode ? 'bg-slate-100 text-slate-700' : 'text-gray-400 hover:bg-gray-50'
                }`}
              >
                <span>Voice Output</span>
                <i className={`fas ${voiceMode ? 'fa-volume-up text-brand-500' : 'fa-volume-mute'}`}></i>
              </button>
            </div>
         </div>
      </div>

      {/* Right Panel: Chat */}
      <div className="flex-1 flex flex-col h-[60vh] md:h-full relative">
         {/* Mobile Header Controls */}
         <div className="md:hidden flex gap-2 p-2 absolute top-2 right-2 z-10">
            <button onClick={() => setVoiceMode(!voiceMode)} className={`w-8 h-8 rounded-full shadow bg-white flex items-center justify-center ${voiceMode ? 'text-brand-600' : 'text-gray-400'}`}>
              <i className={`fas ${voiceMode ? 'fa-volume-up' : 'fa-volume-mute'}`}></i>
            </button>
         </div>

        <div className="flex-1 overflow-y-auto p-4 scroll-smooth">
          {messages.map(msg => (
            <ChatMessage key={msg.id} message={msg} showDebug={showDebug} />
          ))}
          {isLoading && (
            <div className="flex justify-start mb-4">
               <div className="bg-white border border-gray-200 px-4 py-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
                 <div className="flex space-x-1">
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce delay-75"></div>
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce delay-150"></div>
                 </div>
                 <span className="text-xs text-gray-400 ml-2">Thinking...</span>
               </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        <InputArea 
          onSend={processUserRequest} 
          onSendAudio={handleAudioSend}
          isLoading={isLoading} 
          voiceMode={true} // Always allow voice input now that it's robust
        />
      </div>
    </div>
  );
};

export default App;
